// ============================================
// Verifica horário comercial (Seg-Sex, 9h-18h BRT)
// e calcula batch size conforme warm-up
// ============================================

// Se em modo homolog (sdr_config.environment = 'homolog'), bypassa horário comercial
const _sdrConfig = $('Supabase - Lê Config').first().json;
if (_sdrConfig.environment === 'homolog') {
  return [{ json: {
    skip: false,
    batchSize: 1,
    dailyCap: 9999,
    minDelayS: 1,
    maxDelayS: 2,
    hour: new Date(new Date().toLocaleString('en-US', { timeZone: 'America/Sao_Paulo' })).getHours(),
    day: new Date(new Date().toLocaleString('en-US', { timeZone: 'America/Sao_Paulo' })).getDay(),
    bypass: true,
    reason: 'homolog_mode'
  } }];
}

// Se disparado pelo loop do inbound (source = inbound_cycle), bypassa horário
const body = $input.first().json.body || $input.first().json;
if (body.source === 'inbound_cycle') {
  return [{ json: {
    skip: false,
    batchSize: 1,
    dailyCap: 9999,
    minDelayS: 5,
    maxDelayS: 10,
    hour: new Date().getHours(),
    day: new Date().getDay(),
    bypass: true,
    reason: 'inbound_cycle_trigger'
  } }];
}

const now = new Date();

// Converte para BRT (UTC-3)
const brt = new Date(now.toLocaleString('en-US', { timeZone: 'America/Sao_Paulo' }));
const hour = brt.getHours();
const day = brt.getDay(); // 0=Dom, 6=Sab

// Fora do horário comercial?
if (day === 0 || day === 6 || hour < 9 || hour >= 18) {
  return [{ json: { skip: true, reason: 'fora_horario_comercial', hour, day } }];
}

// Sexta depois das 16h - não envia (expira no fim de semana)
if (day === 5 && hour >= 16) {
  return [{ json: { skip: true, reason: 'sexta_tarde', hour, day } }];
}

// Warm-up config (ajustar conforme semana)
// Semana 1: batch=5, cap=30
// Semana 2: batch=10, cap=80
// Semana 3: batch=15, cap=150
// Semana 4+: batch=20, cap=250
const BATCH_SIZE = 5;
const DAILY_CAP = 30;
const MIN_DELAY_S = 60;
const MAX_DELAY_S = 120;

return [{ json: {
  skip: false,
  batchSize: BATCH_SIZE,
  dailyCap: DAILY_CAP,
  minDelayS: MIN_DELAY_S,
  maxDelayS: MAX_DELAY_S,
  hour,
  day
} }];

// Verifica se atingiu o cap diário
const config = $('Horário Comercial?').first().json;
const todayCount = parseInt($input.first().json.today_count) || 0;

if (todayCount >= config.dailyCap) {
  return [{ json: { skip: true, reason: 'daily_cap_atingido', todayCount, dailyCap: config.dailyCap } }];
}

return [{ json: {
  skip: false,
  todayCount,
  remaining: config.dailyCap - todayCount,
  batchSize: Math.min(config.batchSize, config.dailyCap - todayCount),
  minDelayS: config.minDelayS,
  maxDelayS: config.maxDelayS
} }];

// Supabase RPC via HTTP retorna array [{...}]
// Extrai o primeiro elemento e valida existência de clínica.
// Retornar [] para execução (sem Filter node — evita problema de conditions JSON)
const result = $input.first().json;
const clinic = Array.isArray(result) ? result[0] : result;

// Sem clínica disponível: para execução silenciosamente
if (!clinic || !clinic.out_clinic_phone) {
  return [];
}

return [{ json: clinic }];

// UPSERT sempre retorna o lead com id (novo ou existente)
// Retorna [] apenas se houve erro inesperado (sem id)
const lead = $input.first().json;

if (!lead?.id) {
  return [];
}

return [{ json: lead }];

