// ============================================
// Extrai mensagem gerada pela SDR Iris (FastAPI)
// Calcula delay aleatório para cadência humanizada
// remote_jid sempre usa o telefone REAL da clínica.
// O redirecionamento para homolog é feito no nó 'Roteamento Homolog'.
// ============================================

const lead = $('Lead Inserido?').first().json;
const fastapi = $input.first().json;
const config = $('Atingiu Cap?').first().json;

// Nome curto extraído pela LLM (fallback: nome original do CRM)
const shortName = $('FastAPI - Extrai Nome Curto').first().json.short_name || lead.clinic_name;

// Mensagem gerada pela SDR Iris via FastAPI
const message = fastapi.response_message;

// Sem mensagem: para execução silenciosamente
if (!message) {
  return [];
}

// Delay aleatório entre min e max (fallback seguro se config não disponível)
const minDelay = config?.minDelayS ?? 30;
const maxDelay = config?.maxDelayS ?? 60;
const delayS = minDelay + Math.floor(Math.random() * Math.max(1, maxDelay - minDelay));

// remote_jid: sempre o telefone real da clínica (nunca o TEST_PHONE)
const remote_jid = lead.clinic_phone.replace(/\D/g, '') + '@s.whatsapp.net';

return [{
  json: {
    ...lead,
    clinic_name: shortName,
    remote_jid,
    greetingMessage: message,
    delaySec: delayS
  }
}];

