// Roteamento Homolog
// Única responsabilidade: substituir o destino do envio WhatsApp quando em modo homolog.
// O banco já foi gravado com os dados reais — só o destino da mensagem muda aqui.
// Fonte de verdade: sdr_config.environment (lido pelo nó "Supabase - Lê Config" no início do fluxo).

const data = $input.first().json;
const config = $('Supabase - Lê Config').first().json;

// send_jid: destino real do envio WhatsApp
// remote_jid (gravado no banco) permanece com o JID real da clínica
const send_jid = config.environment === 'homolog'
  ? (config.homolog_phone || '').replace(/\D/g, '') + '@s.whatsapp.net'
  : data.remote_jid;

return [{ json: { ...data, send_jid } }];

